#include <stdio.h>
#include <math.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, K, S;
        scanf("%d %d %d", &N, &K, &S);
        int totalChocolates = K * S;
        int minDays = ceil((double)totalChocolates / N);
        int sundays = S / 7;
        if (minDays > S - sundays) {
            printf("-1\n");
        } else {
            printf("%d\n", minDays);
        }
    }
    return 0;
}

