code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int K = sc.nextInt();
            int S = sc.nextInt();
            int totalChocolates = K * S;
            int minDays = (int)Math.ceil((double)totalChocolates / N);
            int sundays = S / 7;
            if (minDays > S - sundays) {
                System.out.println(-1);
            } else {
                System.out.println(minDays);
            }
        }
    }
}

