const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => lines[idx++];
const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const [N, K, S] = readline().split(' ').map(x => parseInt(x));
    const totalChocolates = K * S;
    const minDays = Math.ceil(totalChocolates / N);
    const sundays = Math.floor(S / 7);
    if (minDays > S - sundays) {
        console.log(-1);
    } else {
        console.log(minDays);
    }
}

